public class MaintenanceTraining : TrainingContentBase
{
    public MaintenanceTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Predictive Maintenance Overview",
            Slug = "maintenance-overview",
            Summary = "What predictive maintenance is, how failure predictions and confidence work, severity and the prediction lifecycle, and how to acknowledge, schedule, resolve, or dismiss predictions.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/maintenance/predictions"]""",
            Tags = """["maintenance","assets","predictive"]""",
            ContentJson = """{"body":"## Predictive Maintenance Overview\n\nPredictive Maintenance watches your equipment and warns you before it breaks. Instead of waiting for a machine to fail or running maintenance on a fixed calendar, the system spots likely failures ahead of time and gives you a prioritized list of what to handle. The goal is simple: fix the right thing at the right time, and avoid surprise downtime.\n\nYou don't add predictions yourself — the system creates them from equipment data. What you *do* on this page is respond: review a prediction, schedule maintenance to fix it, resolve it once the work is done, or flag it if the forecast was wrong.\n\n### What Is a Prediction?\n\nA **prediction** is a forecast that a piece of equipment will hit a specific problem by a certain date. Each one tells you:\n- The **equipment** it's about\n- The **type** of problem coming (for example, a bearing or coolant issue)\n- How **urgent** it is — Critical, High, Medium, or Low\n- How **confident** the forecast is\n- When the failure is **expected**\n- Where it **stands** right now\n\n### Confidence and Urgency\n\nThese two work together to help you decide what to handle first:\n- **Confidence** is how sure the forecast is, from 0 to 100 percent. A high number means the system is confident; a low one is more of a guess. Use it to judge how much to trust a prediction.\n- **Urgency** is about how serious and time-sensitive the failure is. **Critical** could fail very soon and needs attention now; **High** is likely to fail within days; **Medium** is a moderate risk worth planning for; **Low** is a low risk to keep an eye on.\n\nAn urgent prediction the system is very confident about is the kind to handle first.\n\n### Where a Prediction Stands\n\nEvery prediction moves through a set of stages:\n\n1. **Predicted** — Brand new. The system spotted a likely failure and it needs your attention. Still open.\n2. **Acknowledged** — You've reviewed it. Still open, but now on your radar and waiting for maintenance to be scheduled.\n3. **Maintenance Scheduled** — A maintenance job is planned to fix it. The work to prevent the failure is set up.\n4. **Resolved** — The work is done and you've closed it out with notes. Finished.\n5. **False Positive** — You decided the forecast was wrong and closed it with a reason. Finished.\n6. **Expired** — The predicted date came and went, so it no longer applies. Finished.\n\nThe first three are *open*; the last three are *finished*. By default the page shows only open predictions, so you focus on what still needs action.\n\n### The Summary Cards\n\nAcross the top of the page, a row of cards sums up the whole picture: how many predictions are active, how many are urgent (highlighted), how many are waiting for you to review, how many have maintenance planned, how accurate the forecasts have been, and how much downtime you've avoided. Together they give leadership a quick health read of the program.\n\n### Responding to a Prediction\n\nEach prediction offers actions that fit where it stands:\n- **Mark Reviewed** — On a new prediction. Notes that you've seen it and moves it to Acknowledged.\n- **Schedule Maintenance** — On new or reviewed predictions. Creates a linked maintenance job to fix the problem and moves it to Maintenance Scheduled.\n- **Resolve** — On any open prediction. Opens a panel for your notes, then closes it as Resolved.\n- **Flag as Wrong** — On any open prediction. Opens a panel for a reason, then closes it as a False Positive.\n\nResolving and flagging both record notes, which — along with whether the forecast proved right — help the system track its accuracy over time.\n\n### How Predictions Connect to Other Features\n\n**Equipment:** Every prediction points to the machine it concerns, tying the maintenance view to your equipment records and scheduling.\n\n**Maintenance Jobs:** Scheduling maintenance creates a linked job — the actual planned work that heads off the predicted failure.\n\n**Getting Smarter Over Time:** When you resolve a prediction or flag it as wrong, you're telling the system whether it was right. The accuracy shown on the summary cards reflects this feedback, so the forecasts improve over time.\n\n### When to Use Predictive Maintenance\n\n- When you want to catch failures before they cause surprise downtime\n- When deciding which machines need attention first — sort by urgency and confidence\n- When you've looked at a prediction and want it on your radar — mark it reviewed\n- When you're ready to plan the fix — schedule maintenance to create a linked job\n- When the work is done — resolve the prediction with notes\n- When the forecast was wrong — flag it so the system learns","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Predictive Maintenance — Guided Tour",
            Slug = "maintenance-walkthrough",
            Summary = "A guided tour of the predictions page: the KPI strip, severity and status filters, the predictions table, and the acknowledge, schedule, resolve, and false-positive actions.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/maintenance/predictions"]""",
            Tags = """["maintenance","assets","predictive","walkthrough"]""",
            ContentJson = """{"appRoute":"/maintenance/predictions","startButtonLabel":"Tour Predictive Maintenance","steps":[{"element":".kpi-strip","popover":{"title":"Health at a Glance","description":"These cards sum up the whole program in one look: how many predictions are active, how many are urgent, how many are waiting on you, how many have maintenance planned, how accurate the forecasts have been, and how much downtime you've avoided.","side":"bottom"}},{"element":".kpi-strip","popover":{"title":"Urgent Predictions","description":"The highlighted card shows how many predictions are urgent — equipment that could fail very soon and needs attention now. When this number isn't zero, start with those rows in the table below.","side":"bottom"}},{"element":"app-toolbar","popover":{"title":"Filters","description":"Narrow the list with the urgency and status filters. By default you see only predictions that still need action, and closed ones are hidden.","side":"bottom"}},{"element":"app-toolbar app-select","popover":{"title":"Filter by Urgency and Status","description":"Pick an urgency level in the first menu and a status in the second. Combine them to focus in — for example, all urgent predictions still waiting for you to review.","side":"bottom"}},{"element":"[tableId='maintenance-predictions']","popover":{"title":"The Predictions List","description":"Each row is one prediction — the equipment, what kind of problem is coming, how urgent it is, how sure the forecast is, when it's expected, and where it stands. Click a column heading to sort, so the most urgent items rise to the top.","side":"top"}},{"element":"[tableId='maintenance-predictions']","popover":{"title":"Act on a Prediction","description":"Each row shows buttons that fit its status. Mark it reviewed once you've seen it, schedule the maintenance to fix it, resolve it when the work is done, or flag it if the forecast was wrong.","side":"top"}},{"element":".toolbar__hint","popover":{"title":"It Learns Over Time","description":"Every time you review, schedule, resolve, or flag a prediction, you tell the system how it did. That feedback improves the accuracy of future forecasts.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Predictive Maintenance Field Reference",
            Slug = "maintenance-field-reference",
            Summary = "Complete reference for every KPI, filter, table column, severity, status, action, and dialog field in the Predictive Maintenance module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/maintenance/predictions"]""",
            Tags = """["maintenance","assets","predictive","reference"]""",
            ContentJson = """{"title":"Predictive Maintenance Field Reference","groups":[{"heading":"Summary Cards (Top of Page)","items":[{"label":"Active Predictions","value":"How many predictions are still open and need attention."},{"label":"Critical","value":"How many predictions are urgent. Shown on a highlighted card so it stands out."},{"label":"Pending Acknowledgment","value":"How many new predictions are waiting for you to review them."},{"label":"Maintenance Scheduled","value":"How many predictions already have maintenance planned to fix them."},{"label":"Model Accuracy","value":"How often the forecasts have proven right, shown as a percentage."},{"label":"Downtime Prevented","value":"The estimated hours of downtime you've avoided by acting on predictions."}]},{"heading":"Filters","items":[{"label":"Urgency","value":"Pick a level — Critical, High, Medium, Low, or all — to show only predictions of that urgency."},{"label":"Status","value":"Pick where a prediction stands, or show all. Starts on open predictions only, so you see just what still needs action."}]},{"heading":"Urgency Levels","items":[{"label":"Critical","value":"Could fail very soon and needs attention now. Handle these first."},{"label":"High","value":"Likely to fail within days."},{"label":"Medium","value":"A moderate risk — worth planning a fix."},{"label":"Low","value":"A low risk. Keep an eye on it."}]},{"heading":"Where a Prediction Stands","items":[{"label":"Predicted","value":"Brand new. The system spotted a likely failure and it needs your attention. Still open — you can review it, schedule a fix, resolve it, or flag it as wrong."},{"label":"Acknowledged","value":"You've reviewed it but haven't planned a fix yet. Still open — you can schedule a fix, resolve it, or flag it as wrong."},{"label":"Maintenance Scheduled","value":"A maintenance job is planned to fix it. Still open — you can resolve it or flag it as wrong."},{"label":"Resolved","value":"The work is done and you closed it out with notes. Finished."},{"label":"False Positive","value":"You decided the forecast was wrong and closed it with a reason. Finished."},{"label":"Expired","value":"The predicted date came and went, so it no longer applies. Finished."}]},{"heading":"List Columns","items":[{"label":"Work Center","value":"The equipment the prediction is about. Click to sort."},{"label":"Type","value":"What kind of problem is coming. Click to sort."},{"label":"Urgency","value":"A colored label showing how urgent it is — Critical, High, Medium, or Low. Click to sort."},{"label":"Confidence","value":"How sure the forecast is, shown as a percentage. Click to sort."},{"label":"Predicted Failure","value":"When the failure is expected, with date and time. Click to sort."},{"label":"Status","value":"A colored label showing where the prediction stands. Click to sort."},{"label":"Actions","value":"The buttons for reviewing, scheduling, resolving, or flagging — whichever fit the current status."}]},{"heading":"Row Actions (Depend on Status)","items":[{"label":"Mark Reviewed","value":"Shown on a new prediction. Notes that you've seen it and moves it to Acknowledged."},{"label":"Schedule Maintenance","value":"Shown on new or reviewed predictions. Creates a linked maintenance job to fix the problem and moves it to Maintenance Scheduled."},{"label":"Resolve","value":"Shown on any open prediction. Opens a panel for your notes, then closes it as Resolved."},{"label":"Flag as Wrong","value":"Shown on any open prediction. Opens a panel for a reason, then closes it as a False Positive."}]},{"heading":"Resolve / Flag Panel","items":[{"label":"Title","value":"Reads 'Resolve Prediction' when you're closing out finished work, or 'Mark as False Positive' when you're flagging a wrong forecast."},{"label":"Notes (required)","value":"Type what you did to fix it, or why the forecast was wrong. Required, up to 2000 characters."},{"label":"Cancel","value":"Closes the panel without saving."},{"label":"Confirm","value":"Saves your notes and closes the prediction. Stays greyed out until you've filled in the notes."}]},{"heading":"Key Ideas","items":[{"label":"Prediction","value":"A forecast that a specific piece of equipment will hit a specific problem by a certain date."},{"label":"Confidence","value":"How sure the forecast is, from 0 to 100 percent. Use it to judge how much to trust the prediction."},{"label":"Urgency","value":"How serious and time-sensitive the coming failure is — Critical, High, Medium, or Low. Use it to decide what to handle first."},{"label":"Open vs Finished","value":"Predicted, Acknowledged, and Maintenance Scheduled still need action; Resolved, False Positive, and Expired are done."},{"label":"Maintenance Job","value":"The planned work that scheduling sets up and links to a prediction to head off the failure."},{"label":"Accuracy Feedback","value":"Resolving or flagging a prediction tells the system whether it was right, which improves future forecasts."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Predictive Maintenance Knowledge Check",
            Slug = "maintenance-quiz",
            Summary = "Test your knowledge of the Predictive Maintenance module: predictions, confidence, severity, the status lifecycle, and the acknowledge/schedule/resolve/false-positive actions.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/maintenance/predictions"]""",
            Tags = """["maintenance","assets","predictive","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"mn1","text":"Where do the predictions on this page come from?","options":[{"id":"a","text":"You click a 'New Prediction' button and fill out a form"},{"id":"b","text":"The system creates them from equipment data — you can't add them by hand; your job is to respond to them","isCorrect":true},{"id":"c","text":"They are imported from purchase orders"},{"id":"d","text":"Customers enter them through a portal"}],"explanation":"You don't add predictions yourself. The system creates them from equipment data. Your job on this page is to respond — review, schedule maintenance, resolve, or flag a forecast that was wrong."},{"id":"mn2","text":"What does the confidence percentage on a prediction tell you?","options":[{"id":"a","text":"How much of the equipment's useful life is left"},{"id":"b","text":"How sure the forecast is that the prediction is correct, from 0 to 100 percent","isCorrect":true},{"id":"c","text":"The discount on the maintenance cost"},{"id":"d","text":"How many similar machines have failed this year"}],"explanation":"Confidence is how sure the forecast is, from 0 to 100 percent. A high number means the system is confident; use it to decide how much to trust a prediction when you're sorting out what to handle."},{"id":"mn3","text":"Which urgency level means the equipment could fail very soon and needs attention now?","options":[{"id":"a","text":"Low"},{"id":"b","text":"Medium"},{"id":"c","text":"Critical","isCorrect":true},{"id":"d","text":"High"}],"explanation":"Critical means the equipment could fail very soon and needs attention now — handle these first. High means failure is likely within days, Medium is a moderate risk worth planning for, and Low is a low risk to keep an eye on."},{"id":"mn4","text":"What is the normal path a prediction follows from new to fixed?","options":[{"id":"a","text":"Open, then Working, then Done"},{"id":"b","text":"Predicted, then Acknowledged, then Maintenance Scheduled, then Resolved","isCorrect":true},{"id":"c","text":"Draft, then Sent, then Accepted, then Closed"},{"id":"d","text":"New, then Triaged, then Escalated, then Archived"}],"explanation":"A prediction starts as Predicted, becomes Acknowledged once you review it, moves to Maintenance Scheduled when a job is set up to fix it, and ends as Resolved when the work is done and you close it with notes. (False Positive and Expired are the other two ways it can finish.)"},{"id":"mn5","text":"When you first open the page, the status filter shows only open predictions. What does that include?","options":[{"id":"a","text":"Every prediction ever made"},{"id":"b","text":"Only predictions that still need action — new ones, reviewed ones, and ones with maintenance scheduled — hiding the finished ones","isCorrect":true},{"id":"c","text":"Only urgent predictions"},{"id":"d","text":"Only predictions that were flagged as wrong"}],"explanation":"By default you see the three open states — Predicted, Acknowledged, and Maintenance Scheduled — and the finished ones (Resolved, False Positive, Expired) are hidden, so you focus on what still needs action."},{"id":"mn6","text":"You've looked at a new prediction and want to put it on your radar without planning any work yet. What do you do?","options":[{"id":"a","text":"Resolve it"},{"id":"b","text":"Mark it reviewed — it moves to Acknowledged","isCorrect":true},{"id":"c","text":"Flag it as wrong"},{"id":"d","text":"Delete the prediction"}],"explanation":"Marking a new prediction reviewed moves it to Acknowledged — still open, but now on your radar and waiting for maintenance to be scheduled."},{"id":"mn7","text":"What happens when you schedule maintenance on a prediction?","options":[{"id":"a","text":"The prediction is permanently deleted"},{"id":"b","text":"A maintenance job is created and linked to it, and it moves to Maintenance Scheduled","isCorrect":true},{"id":"c","text":"The equipment is immediately taken offline"},{"id":"d","text":"An invoice is generated for the repair"}],"explanation":"Scheduling maintenance (available on new or reviewed predictions) creates a linked maintenance job — the planned work to head off the failure — and moves the prediction to Maintenance Scheduled."},{"id":"mn8","text":"You decide a prediction was wrong. What do you do, and what's required?","options":[{"id":"a","text":"Flag it as wrong; nothing else is needed"},{"id":"b","text":"Flag it as wrong, which opens a panel where you enter a required reason before confirming; the prediction closes as a False Positive","isCorrect":true},{"id":"c","text":"Change its urgency to Low"},{"id":"d","text":"Wait for it to expire on its own"}],"explanation":"Flagging a prediction as wrong opens a panel with a required reason (up to 2000 characters). After you enter the reason and confirm, it closes as a False Positive. This feedback helps improve future forecasts."},{"id":"mn9","text":"How are urgency and confidence different when you're sorting out predictions?","options":[{"id":"a","text":"They are the same thing on different scales"},{"id":"b","text":"Urgency is how serious and time-sensitive the failure is; confidence is how sure the forecast is that it's correct","isCorrect":true},{"id":"c","text":"Urgency is set by the user; confidence is set by the customer"},{"id":"d","text":"Urgency applies to the equipment; confidence applies to the work order"}],"explanation":"Urgency tells you how serious and time-sensitive a failure is (Critical, High, Medium, Low), while confidence tells you how sure the forecast is. An urgent prediction the system is very confident about is the kind to handle first."},{"id":"mn10","text":"When you resolve a prediction, what must you provide?","options":[{"id":"a","text":"Nothing — you just click Confirm"},{"id":"b","text":"Notes about what you did (required, up to 2000 characters)","isCorrect":true},{"id":"c","text":"A photo of the repaired part"},{"id":"d","text":"The cost of the maintenance in dollars"}],"explanation":"Resolving opens a panel with a required notes field (up to 2000 characters). You enter what you did and confirm; the prediction closes as Resolved. The Confirm button stays greyed out until the notes are filled in."},{"id":"mn11","text":"Which summary card is highlighted so it stands out?","options":[{"id":"a","text":"Model Accuracy"},{"id":"b","text":"Downtime Prevented"},{"id":"c","text":"Urgent (Critical) predictions","isCorrect":true},{"id":"d","text":"Active Predictions"}],"explanation":"The Critical card is highlighted because urgent predictions could fail very soon. When that number isn't zero, those items should be your first stop in the list."},{"id":"mn12","text":"How does resolving or flagging predictions help the system over time?","options":[{"id":"a","text":"It has no lasting effect"},{"id":"b","text":"It tells the system whether the forecast was right, which improves the accuracy of future predictions","isCorrect":true},{"id":"c","text":"It automatically increases every machine's capacity"},{"id":"d","text":"It deletes the equipment from the system"}],"explanation":"Resolving or flagging a prediction tells the system whether the forecast proved right. That feedback improves accuracy, so the predictions get better over time."}]}"""
        });

        // ── Advanced Reference (Reference) ───────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Maintenance — Advanced Reference",
            Slug = "maintenance-reference",
            Summary = "Power-user and admin reference for Predictive Maintenance: manual TriggerRun, the ML model registry/performance endpoints, work-center risk scores, the prediction data dictionary (RUL, model id/version), the feedback loop, and CAP-MAINT-PREDICTIVE gating.",
            ContentType = TrainingContentType.Reference,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 90,
            AppRoutes = """["/maintenance/predictions"]""",
            Tags = """["maintenance","reference","advanced"]""",
            ContentJson = """{"body":"## Manual Prediction Runs (TriggerRun)\n\nPredictions are normally produced by the model on its own schedule, but an Admin or Manager can force a fresh inference pass for a single work center on demand.\n\n- **Endpoint:** `POST /api/v1/predictions/run/{workCenterId}` returns `202 Accepted` — the run is queued/started, no body is returned.\n- **Authorization:** `[Authorize(Roles = \"Admin,Manager\")]` on top of the controller-wide capability gate. Operators cannot trigger runs.\n- **Handler:** `TriggerPredictionRunCommand` -> `IPredictiveMaintenanceService.TriggerPredictionRunAsync(workCenterId)`.\n- Not surfaced on the `/maintenance/predictions` page today — it is an API-only action (used for testing, after maintenance, or to re-evaluate a work center immediately rather than waiting for the next scheduled pass).\n\n## ML Model Registry & Performance\n\nBehind the predictions sit one or more trained ML models, exposed through two read endpoints (sibling routes under `/api/v1/ml-models`, not under `/predictions`).\n\n- **Registry — `GET /api/v1/ml-models`** returns `MlModelResponseModel[]`: `ModelId`, `Name`, `ModelType`, `Version`, `Status`, `TrainedAt`, `TrainingSampleCount`, and the offline training metrics `Accuracy`, `Precision`, `Recall`, `F1Score` (all nullable), plus `PredictionType` and optional `WorkCenterName` (a model may be global or scoped to one work center).\n- **`Status` (`MlModelStatus`):** `Training`, `Active`, `Inactive`, `Failed`. Only `Active` models produce live predictions.\n- **Performance — `GET /api/v1/ml-models/{modelId}/performance`** returns `MlModelPerformanceResponseModel`: live `Accuracy`, `Precision`, `Recall`, `F1Score`; counts `TotalPredictions`, `TruePredictions`, `FalsePredictions`; `AverageLeadTimeHours` (how far ahead, on average, the model warns); and `AccuracyTrend` — a list of `PredictionAccuracyTrendPoint` (`Period` as a date, `Accuracy`, `Predictions`) for charting drift over time.\n- Performance metrics are fed by the resolve / false-positive / feedback loop — they reflect real outcomes, not just the offline training scores in the registry.\n\n## Work-Center Risk Scores\n\nThe dashboard endpoint `GET /api/v1/predictions/dashboard` (`PredictiveMaintenanceDashboardResponseModel`) carries the KPI counts plus two roll-up lists.\n\n- **`WorkCenterRisks`** — `WorkCenterRiskScoreResponseModel[]`: `WorkCenterId`, `WorkCenterName`, `RiskScore` (a composite urgency score aggregating that work center's open predictions), `HighestSeverityPrediction` (the worst open severity on the asset), and `NextPredictedFailure` (nullable — the soonest forecast failure date).\n- **`UpcomingPredictions`** — `UpcomingPredictionResponseModel[]`: a slim forward-looking feed (`Id`, `WorkCenterName`, `PredictionType`, `ConfidencePercent`, `PredictedFailureDate`, `Severity`).\n- Use risk scores to rank *assets* (which machine needs attention), where the main table ranks individual *predictions*.\n\n## Data Dictionary — Prediction Fields\n\nBeyond the columns shown on the page, each `MaintenancePredictionResponseModel` carries diagnostic fields used for tracing and feedback:\n\n- **`RemainingUsefulLifeHours` (RUL)** — nullable estimate of how many operating hours remain before the predicted failure. Distinct from `PredictedFailureDate` (a calendar date): RUL is in run-time hours, so it accounts for usage, not just elapsed time.\n- **`ModelId` / `ModelVersion`** — which model and which trained version produced this prediction. Critical for auditing: if a model version regresses, you can identify every prediction it emitted.\n- **`InputFeaturesJson`** — the raw feature payload (sensor readings, counters, etc.) the model scored, stored as a JSON string; defaults to `\"{}\"`.\n- **`WasAccurate`** — boolean outcome flag set when the prediction is resolved or feedback is recorded; drives the accuracy metrics above.\n- **`PredictedAt`**, **`AcknowledgedAt`**, **`AcknowledgedByName`**, **`PreventiveMaintenanceJobId`**, **`ResolutionNotes`** — lifecycle audit trail.\n\n## Feedback Loop\n\nSeparate from the in-page Resolve / False-Positive actions, there is an explicit feedback endpoint that closes the ground-truth loop for the model.\n\n- **Endpoint:** `POST /api/v1/predictions/{id}/feedback` -> `204 No Content`.\n- **`RecordPredictionFeedbackRequestModel`:** `ActualFailureOccurred` (bool — did the failure actually happen), `ActualFailureDate` (nullable), `Notes` (nullable). Validation requires the actual-failure date to be present/consistent when a failure is reported.\n- This is the truth signal that updates `WasAccurate` and feeds the live performance metrics — distinct from `ResolutionNotes`, which only document the maintenance work.\n\n## Capability Gating — CAP-MAINT-PREDICTIVE\n\nThe entire `PredictiveMaintenanceController` is gated by `[RequiresCapability(\"CAP-MAINT-PREDICTIVE\")]`.\n\n- When the capability is disabled for an install, every endpoint — predictions list, dashboard, acknowledge/schedule/resolve, manual run, and the `ml-models` routes — returns `403` with the capability envelope, and the `/maintenance/predictions` route is hidden client-side (`capabilityGuard` + `*appCap`).\n- The gate is applied at the controller class level, so there is no per-action override — predictive maintenance is all-or-nothing for an install.\n- Role gating layers on top of the capability gate: Schedule Maintenance and manual TriggerRun additionally require `Admin` or `Manager`.","sections":[]}"""
        });

        Log.Information("Seeded Predictive Maintenance training modules");
    }
}
